import{c as e,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Understanding Multi-Agent LLM Frameworks: A Unified Benchmark and Experimental Analysis","description":"","frontmatter":{"title":"Understanding Multi-Agent LLM Frameworks: A Unified Benchmark and Experimental Analysis","arxiv_id":2602.03128,"authors":"Abdelghny Orogat, Ana Rostam, Essam Mansour","published":"2026-02-03T00:00:00.000Z","source":"https://arxiv.org/abs/2602.03128","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-02-03-multi-agent-llm-frameworks-benchmark-2602-03128.md","filePath":"research/papers/2026-02-03-multi-agent-llm-frameworks-benchmark-2602-03128.md","lastUpdated":1779901665000}'),i={name:"research/papers/2026-02-03-multi-agent-llm-frameworks-benchmark-2602-03128.md"};function s(o,a,l,d,h,m){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="understanding-multi-agent-llm-frameworks-a-unified-benchmark-and-experimental-analysis" tabindex="-1">Understanding Multi-Agent LLM Frameworks: A Unified Benchmark and Experimental Analysis <a class="header-anchor" href="#understanding-multi-agent-llm-frameworks-a-unified-benchmark-and-experimental-analysis" aria-label="Permalink to &quot;Understanding Multi-Agent LLM Frameworks: A Unified Benchmark and Experimental Analysis&quot;">​</a></h1><p><strong>ArXiv</strong>: 2602.03128 | <strong>Date</strong>: 2026-02-03 | <strong>Authors</strong>: Abdelghny Orogat, Ana Rostam, Essam Mansour | <strong>Category</strong>: cs.AI</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>針對多 agent LLM 框架的評估進行系統性研究，填補「框架架構對性能的影響」這一重要空白。核心發現：「架構選擇本身可導致延遲和吞吐量的數量級差距」以及大幅度的準確性差異。</p><h2 id="核心貢獻" tabindex="-1">核心貢獻 <a class="header-anchor" href="#核心貢獻" aria-label="Permalink to &quot;核心貢獻&quot;">​</a></h2><h3 id="mafbench-評估套件" tabindex="-1">MAFBench 評估套件 <a class="header-anchor" href="#mafbench-評估套件" aria-label="Permalink to &quot;MAFBench 評估套件&quot;">​</a></h3><p>統一評估平台，整合現有基準於標準化執行管道，解決碎片化的單能力評估問題。</p><h3 id="架構分類法" tabindex="-1">架構分類法 <a class="header-anchor" href="#架構分類法" aria-label="Permalink to &quot;架構分類法&quot;">​</a></h3><p>建立系統性框架，比較多 agent LLM 系統的基本設計維度：</p><ul><li>協調架構（星形/鏈形/樹形/圖形拓撲）</li><li>記憶行為</li><li>計畫效能</li><li>agent 專業化程度</li><li>任務協調機制</li></ul><h2 id="主要量化發現" tabindex="-1">主要量化發現 <a class="header-anchor" href="#主要量化發現" aria-label="Permalink to &quot;主要量化發現&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>框架架構影響</th></tr></thead><tbody><tr><td><strong>延遲</strong></td><td>純框架選擇即可增加 <strong>&gt;100×</strong> 回應時間</td></tr><tr><td><strong>計畫準確率</strong></td><td>不同架構間最多降低 <strong>30%</strong></td></tr><tr><td><strong>協調成功率</strong></td><td>從 <strong>&gt;90% 降至 &lt;30%</strong>（僅因框架不同）</td></tr></tbody></table><p><strong>關鍵洞見</strong>：框架架構本身（非模型）決定了大部分性能差異。25 頁，9 圖，13 表。</p><h2 id="評估維度" tabindex="-1">評估維度 <a class="header-anchor" href="#評估維度" aria-label="Permalink to &quot;評估維度&quot;">​</a></h2><ol><li>協調開銷（Orchestration overhead）</li><li>記憶行為（Memory behavior）</li><li>計畫效能（Planning effectiveness）</li><li>agent 專業化（Agent specialization）</li><li>任務協調（Task coordination）</li></ol><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>確認「Harness &gt; Model」原則在多 agent 框架層面的普適性：選擇正確的框架拓撲比選擇更強的模型更重要。</p><p>與現有論文 <code>2026-04-07-agent-harness-survey</code>（H=(E,T,C,S,L,V) 六元組）形成互補：本文提供多 agent 框架的 empirical 量化依據。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Agent Architecture &amp; Coordination / Benchmark &amp; Evaluation</strong> — 多 agent 框架架構影響的首個系統性量化研究，100× 延遲差距是跨框架比較的重要基準。</p>',20)])])}const p=e(i,[["render",s]]);export{g as __pageData,p as default};
